 local function SetDYCData(inst, key1, key2, value) if not inst.dycEntityData then inst.dycEntityData = {} end if not inst.dycEntityData[key1] then inst.dycEntityData[key1] = {} end inst.dycEntityData[key1][key2] = value end local animStateFnChanged = false local entityDone = false local TheInst = nil local animToInst = {} local oldFn = _G.CreateEntity _G.CreateEntity = function(...) local inst = oldFn(...) TheInst = inst if not entityDone and inst.entity then entityDone = true local mt = getmetatable(inst.entity) local idx = mt and mt.__index local oldAddAnimState = idx and idx.AddAnimState if oldAddAnimState then idx.AddAnimState = function(...) local anim = oldAddAnimState(...) animToInst[anim] = TheInst if not animStateFnChanged then animStateFnChanged = true local mtAnim = getmetatable(anim) local idxAnim = mtAnim and mtAnim.__index local oldSetBank = idxAnim and idxAnim.SetBank if oldSetBank then idxAnim.SetBank = function(self, bank, ...) local result = oldSetBank(self, bank, ...) SetDYCData(animToInst[self] or TheInst, "AnimState" , "bank" , bank) return result end end local oldSetBuild = idxAnim and idxAnim.SetBuild if oldSetBuild then idxAnim.SetBuild = function(self, build, ...) local result = oldSetBuild(self, build, ...) SetDYCData(animToInst[self] or TheInst, "AnimState" , "build" , build) return result end end local oldClearOverrideSymbol = idxAnim and idxAnim.ClearOverrideSymbol if oldClearOverrideSymbol then idxAnim.ClearOverrideSymbol = function(self, obj, ...) local result = oldClearOverrideSymbol(self, obj, ...) if obj and type(obj) == "string" then obj = obj:lower() SetDYCData(animToInst[self] or TheInst, "AnimState" , "orb_"..obj, nil) SetDYCData(animToInst[self] or TheInst, "AnimState" , "ors_"..obj, nil) SetDYCData(animToInst[self] or TheInst, "AnimState" , "orv_"..obj, false) end return result end end local oldOverrideSymbol = idxAnim and idxAnim.OverrideSymbol if oldOverrideSymbol then idxAnim.OverrideSymbol = function(self, obj, swapBuild, swapSymbol, ...) local result = oldOverrideSymbol(self, obj, swapBuild, swapSymbol, ...) if obj and type(obj) == "string" then obj = obj:lower() SetDYCData(animToInst[self] or TheInst, "AnimState" , "orb_"..obj, swapBuild) SetDYCData(animToInst[self] or TheInst, "AnimState" , "ors_"..obj, swapSymbol) SetDYCData(animToInst[self] or TheInst, "AnimState" , "orv_"..obj, true) end return result end end local oldShow = idxAnim and idxAnim.Show if oldShow then idxAnim.Show = function(self, obj, ...) local result = oldShow(self, obj, ...) if obj and type(obj) == "string" then obj = obj:lower() SetDYCData(animToInst[self] or TheInst, "AnimState" , "vis_"..obj, true) end return result end end local oldHide = idxAnim and idxAnim.Hide if oldHide then idxAnim.Hide = function(self, obj, ...) local result = oldHide(self, obj, ...) if obj and type(obj) == "string" then obj = obj:lower() SetDYCData(animToInst[self] or TheInst, "AnimState" , "vis_"..obj, false) end return result end end end return anim end end end return inst end 